t.script:
//
document.addEventListener('DOMContentLoaded', function() {
        // Global variables
        let pieChart = null;
        let barChart = null;
        let currentData = null;

        // DOM elements
        const purchasePlanSelect = document.getElementById('purchase_plan_select');
        const budgetCpvSelect = document.getElementById('budget_cpv_select');
        const generateBtn = document.getElementById('generate_report');
        const exportBtn = document.getElementById('export_csv');
        const loadingDiv = document.getElementById('loading');
        const resultsSection = document.getElementById('results_section');
        const errorDiv = document.getElementById('error_message');
        const errorText = document.getElementById('error_text');

        // Event listeners
        purchasePlanSelect.addEventListener('change', onPurchasePlanChange);
        budgetCpvSelect.addEventListener('change', onBudgetCpvChange);
        generateBtn.addEventListener('click', generateReport);
        exportBtn.addEventListener('click', exportCSV);

        // Functions
        function onPurchasePlanChange() {
            const planId = purchasePlanSelect.value;
            budgetCpvSelect.innerHTML = '<option value="">იტვირთება...</option>';
            budgetCpvSelect.disabled = true;
            generateBtn.disabled = true;
            hideResults();
            hideError();

            if (planId) {
                loadAnalyticAccounts(planId);
            } else {
                budgetCpvSelect.innerHTML = '<option value="">ჯერ აირჩიეთ შესყიდვების გეგმა...</option>';
            }
        }

        function onBudgetCpvChange() {
            const hasValue = budgetCpvSelect.value;
            generateBtn.disabled = !hasValue;
            exportBtn.disabled = !hasValue;
            hideResults();
            hideError();
        }

        function loadAnalyticAccounts(planId) {
            fetch('/budget/get_budget_cpvs', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: {
                        purchase_plan_id: planId
                    }
                })
            })
            .then(response => response.json())
            .then(data => {
                budgetCpvSelect.innerHTML = '<option value="">აირჩიეთ ანალიტიკური ანგარიში...</option>';

                if (data.result && data.result.length > 0) {
                    data.result.forEach(account => {
                        const option = document.createElement('option');
                        option.value = account.id;
                        option.textContent = account.name;
                        budgetCpvSelect.appendChild(option);
                    });
                    budgetCpvSelect.disabled = false;
                } else {
                    budgetCpvSelect.innerHTML = '<option value="">ანალიტიკური ანგარიშები არ მოიძებნა...</option>';
                }
            })
            .catch(error => {
                console.error('Error loading analytic accounts:', error);
                budgetCpvSelect.innerHTML = '<option value="">შეცდომა ჩატვირთვისას</option>';
                showError('შეცდომა ანალიტიკური ანგარიშების ჩატვირთვისას: ' + error.message);
            });
        }

        function generateReport() {
            const planId = purchasePlanSelect.value;
            const analyticAccountId = budgetCpvSelect.value;

            if (!planId || !analyticAccountId) {
                showError('გთხოვთ, აირჩიოთ ყველა საჭირო ველი');
                return;
            }

            showLoading();
            hideError();

            fetch('/budget/get_chart_data', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: {
                        purchase_plan_id: planId,
                        budget_cpv_id: analyticAccountId
                    }
                })
            })
            .then(response => response.json())
            .then(data => {
                hideLoading();

                if (data.result && Object.keys(data.result).length > 0) {
                    if (data.result.error) {
                        showError('სერვერის შეცდომა: ' + data.result.error);
                        return;
                    }

                    currentData = data.result;
                    renderReport(currentData);
                    showResults();
                    exportBtn.disabled = false;
                } else {
                    showError('მონაცემები ვერ მოიძებნა არჩეული პარამეტრებისთვის');
                }
            })
            .catch(error => {
                console.error('Error generating report:', error);
                hideLoading();
                showError('შეცდომა ანგარიშის გენერირებისას: ' + error.message);
            });
        }

        function renderReport(data) {
            renderSummaryCards(data.summary);
            renderCharts(data);
            renderTable(data.table_data);
        }

        function renderSummaryCards(summary) {
            const cardsContainer = document.getElementById('summary_cards');
            cardsContainer.innerHTML = '<div class="col-lg-4 col-md-6 mb-3">' +
                '<div class="card bg-gradient-warning text-white shadow">' +
                    '<div class="card-body text-center">' +
                        '<div class="row no-gutters align-items-center">' +
                            '<div class="col mr-2">' +
                                '<div class="text-xs font-weight-bold text-uppercase mb-1">გამოყენებული</div>' +
                                '<div class="h5 mb-0 font-weight-bold">' + summary.total_used.toLocaleString() + '</div>' +
                            '</div>' +
                            '<div class="col-auto">' +
                                '<i class="fa fa-credit-card fa-2x text-white-300"></i>' +
                            '</div>' +
                        '</div>' +
                    '</div>' +
                '</div>' +
            '</div>' +
            '<div class="col-lg-4 col-md-6 mb-3">' +
                '<div class="card bg-gradient-success text-white shadow">' +
                    '<div class="card-body text-center">' +
                        '<div class="row no-gutters align-items-center">' +
                            '<div class="col mr-2">' +
                                '<div class="text-xs font-weight-bold text-uppercase mb-1">დარჩენილი</div>' +
                                '<div class="h5 mb-0 font-weight-bold">' + summary.total_remaining.toLocaleString() + '</div>' +
                            '</div>' +
                            '<div class="col-auto">' +
                                '<i class="fa fa-bank fa-2x text-white-300"></i>' +
                            '</div>' +
                        '</div>' +
                    '</div>' +
                '</div>' +
            '</div>' +
            '<div class="col-lg-4 col-md-6 mb-3">' +
                '<div class="card bg-gradient-info text-white shadow">' +
                    '<div class="card-body text-center">' +
                        '<div class="row no-gutters align-items-center">' +
                            '<div class="col mr-2">' +
                                '<div class="text-xs font-weight-bold text-uppercase mb-1">ხაზების რაოდენობა</div>' +
                                '<div class="h5 mb-0 font-weight-bold">' + summary.lines_count + '</div>' +
                                '<div class="text-xs text-white-50">' + summary.cpv_categories + ' CPV კატეგორია</div>' +
                            '</div>' +
                            '<div class="col-auto">' +
                                '<i class="fa fa-list fa-2x text-white-300"></i>' +
                            '</div>' +
                        '</div>' +
                    '</div>' +
                '</div>' +
            '</div>';
        }

        function renderCharts(data) {
            // Destroy existing charts
            if (pieChart) {
                pieChart.destroy();
                pieChart = null;
            }
            if (barChart) {
                barChart.destroy();
                barChart = null;
            }

            // Pie Chart
            const pieCtx = document.getElementById('pie_chart').getContext('2d');
            pieChart = new Chart(pieCtx, {
                type: 'pie',
                data: {
                    labels: data.pie_chart.labels,
                    datasets: [{
                        data: data.pie_chart.data,
                        backgroundColor: data.pie_chart.colors,
                        borderWidth: 2,
                        borderColor: '#fff'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: {
                            position: 'bottom',
                            labels: {
                                padding: 15,
                                usePointStyle: true
                            }
                        },
                        tooltip: {
                            callbacks: {
                                label: function(context) {
                                    return context.label + ': ' + context.parsed.toLocaleString() + ' ლარი';
                                }
                            }
                        }
                    }
                }
            });

            // Bar Chart
            const barCtx = document.getElementById('bar_chart').getContext('2d');
            barChart = new Chart(barCtx, {
                type: 'bar',
                data: {
                    labels: data.bar_chart.labels,
                    datasets: [
                        {
                            label: 'ბიუჯეტი',
                            data: data.bar_chart.budget_amounts,
                            backgroundColor: '#36A2EB',
                            borderColor: '#36A2EB',
                            borderWidth: 1
                        },
                        {
                            label: 'გამოყენებული',
                            data: data.bar_chart.used_amounts,
                            backgroundColor: '#FF6384',
                            borderColor: '#FF6384',
                            borderWidth: 1
                        },
                        {
                            label: 'დარჩენილი',
                            data: data.bar_chart.remaining_amounts,
                            backgroundColor: '#4BC0C0',
                            borderColor: '#4BC0C0',
                            borderWidth: 1
                        }
                    ]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        y: {
                            beginAtZero: true,
                            ticks: {
                                callback: function(value, index, values) {
                                    return value.toLocaleString() + ' ლარი';
                                }
                            }
                        }
                    },
                    plugins: {
                        legend: {
                            position: 'top'
                        },
                        tooltip: {
                            callbacks: {
                                label: function(context) {
                                    return context.dataset.label + ': ' + context.parsed.y.toLocaleString() + ' ლარი';
                                }
                            }
                        }
                    }
                }
            });
        }

        function renderTable(tableData) {
            const tbody = document.querySelector('#data_table tbody');
            tbody.innerHTML = '';

            if (!tableData || tableData.length === 0) {
                const tr = document.createElement('tr');
                tr.innerHTML = '<td colspan="22" class="text-center text-muted py-4">მონაცემები არ არის</td>';
                tbody.appendChild(tr);
                return;
            }

            // Group data by CPV category
            const groupedData = {};
            tableData.forEach(function(row) {
                if (!groupedData[row.cpv_name]) {
                    groupedData[row.cpv_name] = [];
                }
                groupedData[row.cpv_name].push(row);
            });

            // Render grouped data
            Object.keys(groupedData).forEach(function(cpvName, groupIndex) {
                const rows = groupedData[cpvName];

                // Add a group header row
                if (groupIndex > 0) {
                    const separatorTr = document.createElement('tr');
                    separatorTr.innerHTML = '<td colspan="22" class="bg-light text-center font-weight-bold py-2" style="border-top: 2px solid #dee2e6;"><i class="fa fa-tag mr-2"></i>CPV კატეგორია: ' + cpvName + '</td>';
                    tbody.appendChild(separatorTr);
                } else {
                    const headerTr = document.createElement('tr');
                    headerTr.innerHTML = '<td colspan="22" class="bg-primary text-white text-center font-weight-bold py-2"><i class="fa fa-tag mr-2"></i>CPV კატეგორია: ' + cpvName + '</td>';
                    tbody.appendChild(headerTr);
                }

                // Add data rows for this group
                rows.forEach(function(row, rowIndex) {
                    const tr = document.createElement('tr');
                    tr.className = 'cpv-group-' + groupIndex;

                    if (rowIndex % 2 === 0) {
                        tr.style.backgroundColor = '#f8f9fa';
                    }

                    const curr = row.currency_symbol || '';

                    tr.innerHTML = '<td class="font-weight-bold text-info pl-4">' + row.cpv_name + '</td>' +
                        '<td class="font-weight-medium">' + row.plan_name + '</td>' +
                        '<td class="text-right font-weight-bold text-warning">' + row.used_amount.toLocaleString() + ' ' + curr + '</td>' +
                        '<td>' + row.funding_source + '</td>' +
                        '<td>' + row.purchase_method + '</td>' +
                        '<td>' + row.pricekurant + '</td>' +
                        '<td>' + row.variants + '</td>' +
                        '<td class="text-right">' + row.pu_st_am.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.pu_ac_am.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.pu_diff.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.x_studio_reserved.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.x_studio_remaining_resource.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.pcon_am.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.pc_re_am.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.paim_am.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.pa_re_am.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.budget_lines_allocated.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-right">' + row.remaining_to_allocate.toLocaleString() + ' ' + curr + '</td>' +
                        '<td class="text-muted">' + row.budget_line + '</td>' +
                        '<td class="text-info">' + (row.selected_plan_name || 'N/A') + '</td>';
                    tbody.appendChild(tr);
                });
            });
        }

        function exportCSV() {
            if (!currentData || !currentData.table_data) {
                showError('ექსპორტისთვის საჭირო მონაცემები არ არის');
                return;
            }

            let csv = 'CPV კატეგორია,გეგმის დასახელება,ბიუჯეტის თანხა,გამოყენებული თანხა,დარჩენილი რესურსი,დაფინანსების წყარო,შესყიდვის მეთოდი,ფასკურანტი,ვარიანტები,საწყისი თანხა,ფაქტ. თანხა,სხვაობა,დაჯავშნილი,დარჩენილი რესურსი,კონტრაქტის თანხა,კონტრ. დარჩენილი,პერიოდ. თანხა,პერ. დარჩენილი,გამოყოფილი,დასაყოფი,ბიუჯეტის ხაზი,შერჩეული გეგმა\n';

            currentData.table_data.forEach(function(row) {
                csv += '"' + row.cpv_name + '","' + row.plan_name + '",' + 
                    row.budget_amount + ',' + row.used_amount + ',' + row.remaining_amount + ',"' +
                    row.funding_source + '","' + row.purchase_method + '","' + row.pricekurant + '","' +
                    row.variants + '",' + row.pu_st_am + ',' + row.pu_ac_am + ',' + row.pu_diff + ',' +
                    row.x_studio_reserved + ',' + row.x_studio_remaining_resource + ',' + 
                    row.pcon_am + ',' + row.pc_re_am + ',' + row.paim_am + ',' + row.pa_re_am + ',' +
                    row.budget_lines_allocated + ',' + row.remaining_to_allocate + ',"' +
                    row.budget_line + '","' + (row.selected_plan_name || 'N/A') + '"\n';
            });

            const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'budget_cpv_report_' + new Date().toISOString().split('T')[0] + '.csv';
            a.style.display = 'none';
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

        function showLoading() {
            loadingDiv.style.display = 'block';
            resultsSection.style.display = 'none';
            hideError();
        }

        function hideLoading() {
            loadingDiv.style.display = 'none';
        }

        function showResults() {
            resultsSection.style.display = 'block';
            hideError();
        }

        function hideResults() {
            resultsSection.style.display = 'none';
            exportBtn.disabled = true;
            currentData = null;
        }

        function showError(message) {
            errorText.textContent = message;
            errorDiv.style.display = 'block';
            hideLoading();
        }

        function hideError() {
            errorDiv.style.display = 'none';
        }
    });
//
